// AI 처리가 필요한 영상 필터링
// - description/comment 직접 매칭 있는 영상 제외
// - 이미 active ai VP가 있는 영상 제외 (재처리 방지)
var videosResp = $('Get Active Videos').first().json;
var vpsResp = $('Get All VPs').first().json;

var videos = (videosResp && videosResp.list) ? videosResp.list : [];
var allVPs = (vpsResp && vpsResp.list) ? vpsResp.list : [];

// 이미 처리된 video_id 수집 (description/comment/ai 모두 제외)
var skipVideoIds = {};
for (var i = 0; i < allVPs.length; i++) {
  var vp = allVPs[i];
  if (vp.source === 'description' || vp.source === 'comment') {
    skipVideoIds[vp.video_id] = true;  // 직접 링크 있음
  }
  if (vp.source === 'ai' && vp.is_active) {
    skipVideoIds[vp.video_id] = true;  // 이미 AI 처리됨
  }
}

// AI 처리 대상: 아직 미처리된 영상만
var toProcess = [];
for (var j = 0; j < videos.length; j++) {
  var v = videos[j];
  if (!skipVideoIds[v.video_id]) {
    toProcess.push(v);
  }
}

return [{ json: { videos: toProcess, count: toProcess.length } }];

// === WF-YT-AI-MATCH v6: new URL() 제거 (n8n 샌드박스 호환) ===

var GEMINI_KEY = ($env && $env.GEMINI_API_KEY) ? $env.GEMINI_API_KEY : 'AIzaSyC-97PMBNhsqNHWo4Pxye6dY7yOly83xKI';
var NOCODB_TOKEN = 'SIxKK9NtvgsQeLnMQcxbi5pNJGF7tJhnrv6LLGFl';
var YT_BASE = ($env && $env.NOCODB_YOUTUBE_BASE_ID) ? $env.NOCODB_YOUTUBE_BASE_ID : 'pa0dvaitqtslfrx';
var VP_URL = 'https://nocodb.pressco21.com/api/v1/db/data/noco/' + YT_BASE + '/m6wv7he8qwjs43g';
var BULK_PATCH_URL = 'https://nocodb.pressco21.com/api/v1/db/data/bulk/noco/' + YT_BASE + '/m6wv7he8qwjs43g';

var BATCH_LIMIT = 20;
var CALL_DELAY_MS = 400;

// https POST (new URL 불사용 - n8n 샌드박스 호환)
function httpPost(urlStr, headers, bodyObj) {
  return new Promise(function(resolve, reject) {
    var https = require('https');
    var bodyStr = JSON.stringify(bodyObj);
    var req = https.request(urlStr, { method: 'POST', headers: headers }, function(res) {
      var d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() {
        try { resolve(JSON.parse(d)); } catch(e) { resolve({}); }
      });
    });
    req.on('error', function(e) { reject(e); });
    req.write(bodyStr);
    req.end();
  });
}

// https PATCH (new URL 불사용)
function httpPatch(urlStr, headers, bodyObj) {
  return new Promise(function(resolve, reject) {
    var https = require('https');
    var bodyStr = JSON.stringify(bodyObj);
    var req = https.request(urlStr, { method: 'PATCH', headers: headers }, function(res) {
      var d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() { resolve(d); });
    });
    req.on('error', function(e) { reject(e); });
    req.write(bodyStr);
    req.end();
  });
}

// 데이터 로드
var filterData = $('Filter For AI').first().json;
var allTargets = filterData.videos || [];
var aiTargets = allTargets.slice(0, BATCH_LIMIT);

var productsResp = $('Get All Products').first().json;
var allProducts = productsResp.list || [];

var vpsResp = $('Get All VPs').first().json;
var existingVPs = vpsResp.list || [];

// 기존 description/comment VP 세트
var existingDirectSet = {};
for (var i = 0; i < existingVPs.length; i++) {
  var xvp = existingVPs[i];
  if (xvp.source === 'description' || xvp.source === 'comment') {
    existingDirectSet[xvp.video_id + '::' + String(xvp.branduid)] = true;
  }
}

function normalize(s) {
  return (s || '').toLowerCase()
    .replace(/스텐/g, '스탠').replace(/텐드/g, '탠드')
    .replace(/레짐/g, '레진').replace(/켄들/g, '캔들')
    .replace(/에폭씨/g, '에폭시').replace(/레즌/g, '레진')
    .replace(/하바륨/g, '하바리움');
}

async function callGemini(prompt, maxTokens) {
  var url = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-latest:generateContent?key=' + GEMINI_KEY;
  try {
    var resp = await httpPost(url, { 'Content-Type': 'application/json' }, {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.1, maxOutputTokens: maxTokens || 400, thinkingConfig: {thinkingBudget: 0} }
    });
    var candidates = (resp && resp.candidates) ? resp.candidates : [];
    if (candidates.length === 0) return {};
    var parts = ((candidates[0].content || {}).parts || []);
    var text = '';
    for (var pi = 0; pi < parts.length; pi++) {
      if (parts[pi].text) text += parts[pi].text;
    }
    var m = text.match(/\{[\s\S]*\}/);
    if (m) { try { return JSON.parse(m[0]); } catch(e2) { return {}; } }
    return {};
  } catch(e) {
    return { _error: String(e).substring(0, 100) };
  }
}

function scoreProducts(keywords, aiCat, topN) {
  var scored = [];
  for (var j = 0; j < allProducts.length; j++) {
    var prod = allProducts[j];
    var pname = normalize(prod.product_name || '');
    var pkws = [];
    try { pkws = JSON.parse(prod.keywords || '[]'); } catch(e) {}
    var score = 0;
    for (var k = 0; k < keywords.length; k++) {
      var kw = normalize(keywords[k]);
      if (kw.length < 2) continue;
      if (pname.indexOf(kw) >= 0 || pkws.some(function(pk) { return normalize(pk) === kw; })) {
        score += 5;
      } else {
        var wparts = kw.split(/\s+/);
        for (var wp = 0; wp < wparts.length; wp++) {
          if (wparts[wp].length >= 2 && pname.indexOf(wparts[wp]) >= 0) { score += 2; }
        }
      }
    }
    if (aiCat && normalize(prod.category_name || '').indexOf(normalize(aiCat)) >= 0) score += 1;
    if (score > 0) scored.push({ score: score, prod: prod });
  }
  scored.sort(function(a, b) { return b.score - a.score; });
  return scored.slice(0, topN || 20).map(function(item) {
    return {
      branduid: String(item.prod.branduid || ''),
      product_name: item.prod.product_name || '',
      product_price: item.prod.price || 0,
      product_image: item.prod.image_url || '',
      product_url: item.prod.product_url || ('/shop/shopdetail.html?branduid=' + item.prod.branduid),
      score: item.score
    };
  });
}

var processed = 0, inserted = 0, skipped = 0;
var errors = [];

for (var vi = 0; vi < aiTargets.length; vi++) {
  var v = aiTargets[vi];
  var videoId = v.video_id;
  try {
    var title = v.title || '';
    var tags = [];
    try { tags = JSON.parse(v.tags || '[]'); } catch(e) {}
    var cat = v.matched_category || '';

    var s1Prompt = '당신은 한국 공예 재료 쇼핑몰 상품 매칭 전문가입니다.\n다음 YouTube 영상에서 사용된 핵심 재료명을 최대 5개 추출해주세요.\n\n영상 제목: ' + title + '\n';
    if (cat) s1Prompt += '카테고리: ' + cat + '\n';
    if (tags.length > 0) s1Prompt += '태그: ' + tags.slice(0, 5).join(', ') + '\n';
    s1Prompt += '\nJSON으로만 응답:\n{"keywords": ["키워드1"], "category": "압화|레진|캔들|석고|비즈|기타"}';

    var stage1 = await callGemini(s1Prompt, 300);
    var keywords = stage1.keywords || [];
    var aiCat = stage1.category || '';

    if (stage1._error || keywords.length === 0) {
      errors.push(videoId + ':s1:' + (stage1._error || 'no_kw'));
      skipped++; continue;
    }

    var candidates = scoreProducts(keywords, aiCat, 20);
    if (candidates.length === 0) { skipped++; continue; }

    var top10 = candidates.slice(0, 10);
    var candList = top10.map(function(c, idx) {
      return (idx + 1) + '. branduid=' + c.branduid + ' | ' + c.product_name;
    }).join('\n');

    var s2Prompt = '한국 공예 YouTube 영상에서 사용할 재료를 고르는 전문가입니다.\n\n영상 제목: ' + title + '\n키워드: ' + keywords.join(', ') + '\n\n아래 상품에서 실제 사용 재료/도구/용기 최대 4개 선택 (완성품 제외, 원재료만):\n' + candList + '\n\nJSON으로만 응답:\n{"selected_branduids": ["branduid1"]}';

    var stage2 = await callGemini(s2Prompt, 200);
    var selBranduids = stage2.selected_branduids || [];
    var finalCands = candidates.filter(function(c) {
      return selBranduids.indexOf(String(c.branduid)) >= 0;
    });
    if (finalCands.length === 0) finalCands = candidates.slice(0, 4);

    // 기존 keyword/ai VP 비활성화
    var oldVPs = existingVPs.filter(function(vp) {
      return vp.video_id === videoId && (vp.source === 'keyword' || vp.source === 'ai');
    });
    if (oldVPs.length > 0) {
      try {
        await httpPatch(BULK_PATCH_URL,
          { 'xc-token': NOCODB_TOKEN, 'Content-Type': 'application/json' },
          oldVPs.map(function(vp) { return { Id: vp.Id, is_active: false }; })
        );
      } catch(e) {}
    }

    // 새 VP 삽입
    for (var ci = 0; ci < finalCands.length; ci++) {
      var c = finalCands[ci];
      var key = videoId + '::' + String(c.branduid);
      if (existingDirectSet[key]) continue;
      try {
        await httpPost(VP_URL,
          { 'xc-token': NOCODB_TOKEN, 'Content-Type': 'application/json' },
          {
            video_id: videoId, branduid: String(c.branduid),
            product_name: c.product_name, product_price: c.product_price,
            product_image: c.product_image, product_url: c.product_url,
            source: 'ai', confidence: 'medium', match_score: c.score,
            display_order: ci + 1, is_active: true,
            matched_at: new Date().toISOString()
          }
        );
        inserted++;
      } catch(e) {
        errors.push(videoId + ':insert:' + String(e).substring(0, 40));
      }
    }

    processed++;
    if (vi < aiTargets.length - 1) {
      await new Promise(function(r) { setTimeout(r, CALL_DELAY_MS); });
    }
  } catch(e) {
    errors.push(videoId + ':' + String(e).substring(0, 50));
  }
}

return [{ json: {
  processed: processed, inserted: inserted, skipped: skipped,
  total: allTargets.length, batched: aiTargets.length,
  errorCount: errors.length, errors: errors.slice(0, 5)
} }];
